const data = items[0]?.json || {};
const now = new Date();
const date = now.toISOString().split('T')[0];

const btc = data.bitcoin || {};
const eth = data.ethereum || {};
const doge = data.dogecoin || {};

return [{ json: {
  date,
  asset_type: 'crypto',
  bitcoin_usd: btc.usd || 0,
  bitcoin_inr: btc.inr || 0,
  bitcoin_24h_change: Math.round((btc.usd_24h_change || 0) * 100) / 100,
  bitcoin_market_cap_usd: btc.usd_market_cap || 0,
  ethereum_usd: eth.usd || 0,
  ethereum_inr: eth.inr || 0,
  ethereum_24h_change: Math.round((eth.usd_24h_change || 0) * 100) / 100,
  ethereum_market_cap_usd: eth.usd_market_cap || 0,
  dogecoin_usd: doge.usd || 0,
  dogecoin_inr: doge.inr || 0,
  dogecoin_24h_change: Math.round((doge.usd_24h_change || 0) * 100) / 100,
  dogecoin_market_cap_usd: doge.usd_market_cap || 0,
  fetchedAt: now.toISOString(),
  source: 'coingecko'
}}];

const goldCG = items[0]?.json || {};
const now = new Date();
const date = now.toISOString().split('T')[0];

const xaut = goldCG['tether-gold'] || goldCG;
const goldUsd = xaut.usd || 0;
const goldInr = xaut.inr || 0;
const gold24h = Math.round((xaut.usd_24h_change || 0) * 100) / 100;

const troyOzToGram = 31.1035;
const goldUsdPerGram = goldUsd ? Math.round((goldUsd / troyOzToGram) * 100) / 100 : 0;

// Derive USD/INR rate from gold prices if available
const usdToInr = (goldUsd && goldInr) ? Math.round((goldInr / goldUsd) * 100) / 100 : 84.0;
const goldInrPerGram = goldUsdPerGram ? Math.round(goldUsdPerGram * usdToInr) : 0;
const goldInrPer10gram = goldInrPerGram * 10;

return [{ json: {
  date,
  asset_type: 'metals',
  gold_usd_per_oz: goldUsd,
  gold_usd_per_gram: goldUsdPerGram,
  gold_inr_per_gram: goldInrPerGram,
  gold_inr_per_10gram: goldInrPer10gram,
  gold_24h_change: gold24h,
  usd_to_inr_rate: usdToInr,
  fetchedAt: now.toISOString(),
  source: 'coingecko'
}}];

const html = items[0]?.json?.data || items[0]?.json?.body || '';
const now = new Date();
const date = now.toISOString().split('T')[0];

let gold22k = 0, gold24k = 0, silverPerGram = 0, silverPerKg = 0;

try {
  // Try to extract gold price from goodreturns page
  // Pattern: "22 Carat Gold" ... price like "6,850" or "68,500"
  const gold22Match = html.match(/22\s*(?:Carat|K|Kt).*?([\d,]+\.?\d*)\s*(?:\/g|per\s*gram)/i);
  const gold24Match = html.match(/24\s*(?:Carat|K|Kt).*?([\d,]+\.?\d*)\s*(?:\/g|per\s*gram)/i);

  // Alternative: look for price table patterns
  // Gold rate today in India per gram
  const goldPriceMatch = html.match(/gold.*?price.*?today.*?(?:Rs\.?|₹)\s*([\d,]+)/i)
    || html.match(/(?:Rs\.?|₹)\s*([\d,]+).*?(?:per\s*(?:10)?\s*gram|10g)/i);

  // Try multiple patterns for gold 22k per gram  
  if (gold22Match) {
    gold22k = parseFloat(gold22Match[1].replace(/,/g, ''));
  }
  if (gold24Match) {
    gold24k = parseFloat(gold24Match[1].replace(/,/g, ''));
  }

  // If we got per-10-gram price, convert
  if (gold24k > 50000) { gold24k = Math.round(gold24k / 10); }
  if (gold22k > 50000) { gold22k = Math.round(gold22k / 10); }

  if (!gold24k && goldPriceMatch) {
    let price = parseFloat(goldPriceMatch[1].replace(/,/g, ''));
    if (price > 50000) price = Math.round(price / 10);
    gold24k = price;
  }

  // Silver
  const silverMatch = html.match(/silver.*?(?:Rs\.?|₹)\s*([\d,]+\.?\d*)/i)
    || html.match(/(?:Rs\.?|₹)\s*([\d,]+\.?\d*).*?silver/i);
  if (silverMatch) {
    silverPerGram = parseFloat(silverMatch[1].replace(/,/g, ''));
    if (silverPerGram > 500) {
      silverPerKg = silverPerGram;
      silverPerGram = Math.round(silverPerKg / 1000);
    } else {
      silverPerKg = silverPerGram * 1000;
    }
  }
} catch(e) {
  // scraping failed, values stay 0
}

return [{ json: {
  date,
  asset_type: 'metals_inr_scraped',
  gold_22k_inr_per_gram: gold22k,
  gold_24k_inr_per_gram: gold24k,
  gold_24k_inr_per_10gram: gold24k * 10,
  silver_inr_per_gram: silverPerGram,
  silver_inr_per_kg: silverPerKg,
  fetchedAt: now.toISOString(),
  source: 'goodreturns.in'
}}];

// Build requests for top Indian stocks
const stocks = [
  { symbol: 'RELIANCE.NS', name: 'Reliance Industries' },
  { symbol: 'TCS.NS', name: 'TCS' },
  { symbol: 'INFY.NS', name: 'Infosys' },
  { symbol: 'HDFCBANK.NS', name: 'HDFC Bank' },
  { symbol: 'ICICIBANK.NS', name: 'ICICI Bank' },
  { symbol: 'HINDUNILVR.NS', name: 'Hindustan Unilever' },
  { symbol: 'ITC.NS', name: 'ITC' },
  { symbol: 'SBIN.NS', name: 'SBI' },
  { symbol: 'BHARTIARTL.NS', name: 'Bharti Airtel' },
  { symbol: 'WIPRO.NS', name: 'Wipro' }
];

return stocks.map(s => ({ json: s }));

const results = [];
const now = new Date();
const date = now.toISOString().split('T')[0];

for (const item of items) {
  try {
    const chart = item.json?.chart?.result?.[0] || {};
    const meta = chart.meta || {};
    const quotes = chart.indicators?.quote?.[0] || {};
    const closes = quotes.close || [];
    const latestPrice = meta.regularMarketPrice || closes[closes.length - 1] || 0;
    const prevClose = meta.chartPreviousClose || meta.previousClose || closes[closes.length - 2] || 0;
    const change = latestPrice && prevClose ? Math.round((latestPrice - prevClose) * 100) / 100 : 0;
    const changePct = prevClose ? Math.round(((latestPrice - prevClose) / prevClose) * 10000) / 100 : 0;

    results.push({
      json: {
        date,
        asset_type: 'indian_stock',
        symbol: meta.symbol || 'unknown',
        name: meta.shortName || meta.symbol || 'unknown',
        price_inr: Math.round(latestPrice * 100) / 100,
        previous_close: Math.round(prevClose * 100) / 100,
        change: change,
        change_percent: changePct,
        day_high: meta.regularMarketDayHigh || 0,
        day_low: meta.regularMarketDayLow || 0,
        volume: meta.regularMarketVolume || 0,
        currency: meta.currency || 'INR',
        exchange: meta.exchangeName || 'NSE',
        fetchedAt: now.toISOString(),
        source: 'yahoo_finance'
      }
    });
  } catch(e) {
    // skip failed items
  }
}

return results.length ? results : [{ json: { date, asset_type: 'indian_stock', error: 'no data', fetchedAt: now.toISOString() } }];

const data = items[0]?.json || {};
const now = new Date();
const date = now.toISOString().split('T')[0];

try {
  const chart = data.chart?.result?.[0] || data;
  const meta = chart.meta || data;
  const quotes = chart.indicators?.quote?.[0] || {};
  const closes = quotes.close || [];
  const latestPrice = meta.regularMarketPrice || closes[closes.length - 1] || 0;
  const prevClose = meta.chartPreviousClose || closes[closes.length - 2] || 0;
  const change = latestPrice && prevClose ? Math.round((latestPrice - prevClose) * 100) / 100 : 0;
  const changePct = prevClose ? Math.round(((latestPrice - prevClose) / prevClose) * 10000) / 100 : 0;

  return [{ json: {
    date,
    asset_type: 'index',
    symbol: 'NIFTY_50',
    name: 'NIFTY 50',
    price_inr: Math.round(latestPrice * 100) / 100,
    previous_close: Math.round(prevClose * 100) / 100,
    change,
    change_percent: changePct,
    day_high: meta.regularMarketDayHigh || 0,
    day_low: meta.regularMarketDayLow || 0,
    fetchedAt: now.toISOString(),
    source: 'yahoo_finance'
  }}];
} catch(e) {
  return [{ json: { date, asset_type: 'index', symbol: 'NIFTY_50', error: e.message, fetchedAt: now.toISOString() } }];
}

const data = items[0]?.json || {};
const now = new Date();
const date = now.toISOString().split('T')[0];

try {
  const chart = data.chart?.result?.[0] || data;
  const meta = chart.meta || data;
  const quotes = chart.indicators?.quote?.[0] || {};
  const closes = quotes.close || [];
  const latestPrice = meta.regularMarketPrice || closes[closes.length - 1] || 0;
  const prevClose = meta.chartPreviousClose || closes[closes.length - 2] || 0;
  const change = latestPrice && prevClose ? Math.round((latestPrice - prevClose) * 100) / 100 : 0;
  const changePct = prevClose ? Math.round(((latestPrice - prevClose) / prevClose) * 10000) / 100 : 0;

  return [{ json: {
    date,
    asset_type: 'index',
    symbol: 'SENSEX',
    name: 'BSE SENSEX',
    price_inr: Math.round(latestPrice * 100) / 100,
    previous_close: Math.round(prevClose * 100) / 100,
    change,
    change_percent: changePct,
    day_high: meta.regularMarketDayHigh || 0,
    day_low: meta.regularMarketDayLow || 0,
    fetchedAt: now.toISOString(),
    source: 'yahoo_finance'
  }}];
} catch(e) {
  return [{ json: { date, asset_type: 'index', symbol: 'SENSEX', error: e.message, fetchedAt: now.toISOString() } }];
}

// Merge all pricing data into unified records
const allItems = items.map(i => i.json);
const now = new Date();
const date = now.toISOString().split('T')[0];

// Find each section
const crypto = allItems.find(i => i.asset_type === 'crypto') || {};
const metalsCG = allItems.find(i => i.asset_type === 'metals') || {};
const metalsScrape = allItems.find(i => i.asset_type === 'metals_inr_scraped') || {};
const nifty = allItems.find(i => i.asset_type === 'index' && i.symbol === 'NIFTY_50') || {};
const sensex = allItems.find(i => i.asset_type === 'index' && i.symbol === 'SENSEX') || {};
const stocks = allItems.filter(i => i.asset_type === 'indian_stock' && !i.error);

// Use scraped INR prices if available, else CoinGecko derived
const goldInrPerGram = metalsScrape.gold_24k_inr_per_gram || metalsCG.gold_inr_per_gram || 0;
const goldInrPer10gram = metalsScrape.gold_24k_inr_per_10gram || metalsCG.gold_inr_per_10gram || 0;
const silverInrPerGram = metalsScrape.silver_inr_per_gram || 0;
const silverInrPerKg = metalsScrape.silver_inr_per_kg || 0;

// Build the master record for MongoDB / Sheets
const masterRecord = {
  date,
  // Metals
  gold_usd_per_oz: metalsCG.gold_usd_per_oz || 0,
  gold_inr_per_gram: goldInrPerGram,
  gold_inr_per_10gram: goldInrPer10gram,
  gold_22k_inr_per_gram: metalsScrape.gold_22k_inr_per_gram || 0,
  silver_inr_per_gram: silverInrPerGram,
  silver_inr_per_kg: silverInrPerKg,
  // Crypto
  bitcoin_usd: crypto.bitcoin_usd || 0,
  bitcoin_inr: crypto.bitcoin_inr || 0,
  bitcoin_24h_change: crypto.bitcoin_24h_change || 0,
  ethereum_usd: crypto.ethereum_usd || 0,
  ethereum_inr: crypto.ethereum_inr || 0,
  ethereum_24h_change: crypto.ethereum_24h_change || 0,
  dogecoin_usd: crypto.dogecoin_usd || 0,
  dogecoin_inr: crypto.dogecoin_inr || 0,
  dogecoin_24h_change: crypto.dogecoin_24h_change || 0,
  // Indian Market Indices
  nifty50: nifty.price_inr || 0,
  nifty50_change: nifty.change || 0,
  nifty50_change_pct: nifty.change_percent || 0,
  sensex: sensex.price_inr || 0,
  sensex_change: sensex.change || 0,
  sensex_change_pct: sensex.change_percent || 0,
  // Top stocks summary
  top_stocks: stocks.map(s => `${s.symbol}:${s.price_inr}(${s.change_percent}%)`).join(', '),
  // Meta
  usd_to_inr_rate: metalsCG.usd_to_inr_rate || 0,
  fetchedAt: now.toISOString(),
  source: 'coingecko+goodreturns+yahoo'
};

// Skip if all major values are 0 (total failure)
const hasData = masterRecord.gold_usd_per_oz > 0 || masterRecord.bitcoin_usd > 0 || masterRecord.nifty50 > 0;
if (!hasData) {
  return [{ json: { ...masterRecord, _skip: true, error: 'All sources returned 0' } }];
}

return [{ json: masterRecord }];

// Filter out records where _skip is true (all sources failed)
const record = items[0]?.json || {};
if (record._skip) {
  return [];
}
return items;
